@dataclass
class DocumentChunk:
    chunk_id: str
    source: str
    text: str
    metadata: Dict[str, str] = field(default_factory=dict)


class SimpleTextLoader:
    def __init__(self, data_dir: str):
        self.data_dir = data_dir

    def load(self) -> List[Tuple[str, str]]:
        patterns = ["**/*.txt", "**/*.md", "**/*.json"]
        files = []
        for pattern in patterns:
            files.extend(glob.glob(os.path.join(self.data_dir, pattern), recursive=True))
        docs = []
        for path in sorted(set(files)):
            try:
                docs.append((path, self._read_file(path)))
            except Exception:
                continue
        return docs

    def _read_file(self, path: str) -> str:
        ext = os.path.splitext(path)[1].lower()
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            if ext == ".json":
                obj = json.load(f)
                return json.dumps(obj, ensure_ascii=False, indent=2)
            return f.read()


class TextChunker:
    def __init__(self, chunk_size: int = 1200, overlap: int = 200):
        self.chunk_size = chunk_size
        self.overlap = overlap

    def chunk(self, text: str, source: str) -> List[DocumentChunk]:
        text = text.strip()
        if not text:
            return []
        chunks = []
        start = 0
        idx = 0
        while start < len(text):
            end = min(len(text), start + self.chunk_size)
            chunk_text = text[start:end].strip()
            if chunk_text:
                chunk_id = self._make_chunk_id(source, idx, chunk_text)
                chunks.append(DocumentChunk(chunk_id=chunk_id, source=source, text=chunk_text))
                idx += 1
            if end == len(text):
                break
            start = max(0, end - self.overlap)
        return chunks

    def _make_chunk_id(self, source: str, idx: int, text: str) -> str:
        h = hashlib.sha1(f"{source}:{idx}:{text}".encode("utf-8")).hexdigest()
        return h


class VectorStore:
    def __init__(self, embedding_model_name: str = "all-MiniLM-L6-v2"):
        self.embedding_model_name = embedding_model_name
        self.embedder = SentenceTransformer(embedding_model_name)
        self.index = None
        self.chunks: List[DocumentChunk] = []
        self.dim = self.embedder.get_sentence_embedding_dimension()

    def build(self, chunks: List[DocumentChunk]) -> None:
        self.chunks = chunks
        texts = [c.text for c in chunks]
        embeddings = self.embedder.encode(texts, convert_to_numpy=True, normalize_embeddings=True)
        embeddings = embeddings.astype("float32")
        self.index = faiss.IndexFlatIP(self.dim)
        self.index.add(embeddings)

    def add(self, chunks: List[DocumentChunk]) -> None:
        if not chunks:
            return
        if self.index is None:
            self.build(chunks)
            return
        texts = [c.text for c in chunks]
        embeddings = self.embedder.encode(texts, convert_to_numpy=True, normalize_embeddings=True)
        embeddings = embeddings.astype("float32")
        self.index.add(embeddings)
        self.chunks.extend(chunks)

    def search(self, query: str, top_k: int = 5) -> List[DocumentChunk]:
        if self.index is None or not self.chunks:
            return []
        q = self.embedder.encode([query], convert_to_numpy=True, normalize_embeddings=True).astype("float32")
        scores, indices = self.index.search(q, top_k)
        results = []
        for idx in indices[0]:
            if idx < 0 or idx >= len(self.chunks):
                continue
            results.append(self.chunks[idx])
        return results


class RAGSystem:
    def __init__(
        self,
        data_dir: str,
        openai_api_key: Optional[str] = None,
        llm_model: str = "gpt-4o-mini",
        embedding_model_name: str = "all-MiniLM-L6-v2",
        chunk_size: int = 1200,
        overlap: int = 200,
    ):
        self.data_dir = data_dir
        self.loader = SimpleTextLoader(data_dir)
        self.chunker = TextChunker(chunk_size=chunk_size, overlap=overlap)
        self.vector_store = VectorStore(embedding_model_name=embedding_model_name)
        self.client = OpenAI(api_key=openai_api_key or os.getenv("OPENAI_API_KEY"))
        self.llm_model = llm_model

    def ingest(self) -> None:
        docs = self.loader.load()
        chunks: List[DocumentChunk] = []
        for source, text in docs:
            chunks.extend(self.chunker.chunk(text=text, source=source))
        self.vector_store.build(chunks)

    def retrieve(self, query: str, top_k: int = 5) -> List[DocumentChunk]:
        return self.vector_store.search(query, top_k=top_k)

    def build_prompt(self, query: str, retrieved: List[DocumentChunk]) -> List[Dict[str, str]]:
        context_blocks = []
        for i, chunk in enumerate(retrieved, 1):
            context_blocks.append(
                f"[Document {i}]\nSource: {chunk.source}\nChunk ID: {chunk.chunk_id}\nContent:\n{chunk.text}"
            )
        context = "\n\n".join(context_blocks) if context_blocks else "No relevant documents retrieved."
        system_prompt = (
            "You are an internal company knowledge base assistant. "
            "Answer only using the provided context. "
            "If the answer is not in the context, say you do not know. "
            "Cite sources by document number and source path when possible."
        )
        user_prompt = f"Question:\n{query}\n\nRetrieved context:\n{context}"
        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_prompt},
        ]

    def ask(self, query: str, top_k: int = 5) -> str:
        retrieved = self.retrieve(query, top_k=top_k)
        messages = self.build_prompt(query, retrieved)
        response = self.client.chat.completions.create(
            model=self.llm_model,
            messages=messages,
            temperature=0.2,
        )
        return response.choices[0].message.content

    def ask_with_context(self, query: str, top_k: int = 5) -> Dict[str, object]:
        retrieved = self.retrieve(query, top_k=top_k)
        messages = self.build_prompt(query, retrieved)
        response = self.client.chat.completions.create(
            model=self.llm_model,
            messages=messages,
            temperature=0.2,
        )
        return {
            "answer": response.choices[0].message.content,
            "retrieved_documents": [
                {"source": c.source, "chunk_id": c.chunk_id, "text": c.text, "metadata": c.metadata}
                for c in retrieved
            ],
        }


def main():
    data_dir = os.getenv("RAG_DATA_DIR", "./documents")
    rag = RAGSystem(data_dir=data_dir)
    rag.ingest()
    print("RAG system ready. Type your question or 'exit'.")
    while True:
        try:
            query = input("> ").strip()
        except (EOFError, KeyboardInterrupt):
            break
        if not query or query.lower() in {"exit", "quit"}:
            break
        try:
            answer = rag.ask(query, top_k=5)
            print(answer)
            print()
        except Exception as e:
            print(f"Error: {e}")


if __name__ == "__main__":
    main()